#!/usr/bin/env python3
"""Generated by superpower-adapter.

Scaffold / convert project best-practice skill packs and register their wiki
discovery card. This is the MECHANICAL layer only: it creates skeleton files,
carries over bundled assets, registers/updates the `guides/skills.md` discovery
card + companion section index, fixes the index linkage so the page is
discoverable, and validates invariants. It performs NO semantic judgement about
what a skill should contain or how to split it — the `scaffold-practice-skill`
agent decides that and authors the real content.

Commands:
  scaffold       Create a new pack skeleton under <project>/.claude/skills/<name>/.
  convert        Stage a layered pack from an existing skill (non-destructive),
                 carry over bundled files, and report source-content coverage gaps.
  register-card  Upsert the <name> discovery card in <wiki-root>/guides/skills.md,
                 refresh its companion index, and ensure index linkage.
  validate       Check pack invariants + wiki discoverability (+ optional --from coverage).

A skill pack has exactly one fixed file — `SKILL.md` (a thin router). Everything
else (implement.md / review.md / rules.md / examples.md / scripts/ / assets ...)
is an open set created only when asked. The goal of that single invariant is
progressive disclosure: SKILL.md stays small and points at sibling files loaded
on demand.
"""

from __future__ import annotations

import argparse
import json
import re
import shutil
import sys
from pathlib import Path
from typing import Any

sys.path.insert(0, str(Path(__file__).resolve().parent))

from wiki_common import (  # noqa: E402
    AUTO_END,
    AUTO_START,
    WIKI_OPERATION_CREATE,
    WIKI_OPERATION_UPDATE,
    build_wiki_index_graph,
    enforce_wiki_update_authorization,
    replace_auto_section,
    repo_root,
    select_wiki_root,
    write_text_lf,
)
from wiki_generate_section_index import generate_index, index_path_for  # noqa: E402
from wiki_section import list_section_ids, validate_section_markers  # noqa: E402

SKILLS_DIR_REL = Path(".claude") / "skills"
GENERATED_MARKER = "Generated by superpower-adapter"
SKILL_NAME_RE = re.compile(r"^[a-z0-9][a-z0-9-]*$")
FRONTMATTER_RE = re.compile(r"^---\n(.*?)\n---\n", re.DOTALL)
HEADING_RE = re.compile(r"^#{1,6}\s+(.+?)\s*$")
FENCE_RE = re.compile(r"^(`{3,}|~{3,})")
BACKTICK_RE = re.compile(r"`([^`]+)`")

DEFAULT_DESCRIPTION = (
    "TODO(agent): 一句话说明该最佳实践 skill 的适用场景与触发词，供 Claude 按需加载时匹配。"
)
GUIDES_INTRO = (
    "# Guides\n\nUse guides for cross-cutting checklists and thinking prompts, "
    "not low-level implementation contracts.\n"
)
SKILLS_INTRO = (
    "# Skills\n\n本页是项目最佳实践 skill 的发现目录：每个 skill 一个 section，"
    "写明触发场景与必须使用的 skill 名。规范正文保留在对应 skill 包内，本页只负责被 wiki-researcher 发现。\n"
)
ROOT_INTRO = (
    "# Project Wiki\n\nUse this file as the entry point for project-specific wiki pages.\n"
)


class ScaffoldError(Exception):
    pass


def _configure_stdio() -> None:
    for stream in (sys.stdout, sys.stderr):
        if not hasattr(stream, "reconfigure"):
            continue
        try:
            stream.reconfigure(encoding="utf-8", errors="replace", newline="\n")
        except (OSError, ValueError):
            pass


# --------------------------------------------------------------------------- #
# Small helpers
# --------------------------------------------------------------------------- #
def resolve_project(args: argparse.Namespace) -> Path:
    if getattr(args, "project_root", None):
        return Path(args.project_root).resolve()
    return repo_root(Path.cwd())


def require_name(name: str | None) -> str:
    if not name:
        raise ScaffoldError("--name is required")
    if not SKILL_NAME_RE.match(name):
        raise ScaffoldError(
            f"invalid skill name {name!r}; use kebab-case [a-z0-9][a-z0-9-]*"
        )
    return name


def title_from_name(name: str) -> str:
    cleaned = name.replace("-", " ").replace("_", " ").strip()
    if cleaned.isascii():
        return cleaned.title()
    return cleaned


def parse_files(raw: str | None) -> list[str]:
    """Parse a comma-separated list of pack-relative paths (open set)."""
    if not raw:
        return []
    out: list[str] = []
    for item in raw.split(","):
        rel = item.strip().replace("\\", "/").strip("/")
        if not rel:
            continue
        if rel == "SKILL.md":
            # SKILL.md is the mandatory router, handled separately.
            continue
        parts = Path(rel).parts
        if any(part in ("..",) for part in parts) or rel.startswith("/"):
            raise ScaffoldError(f"unsafe pack-relative path: {item!r}")
        if rel not in out:
            out.append(rel)
    return out


def parse_frontmatter(text: str) -> dict[str, str]:
    match = FRONTMATTER_RE.match(text)
    if not match:
        return {}
    fm: dict[str, str] = {}
    for line in match.group(1).splitlines():
        kv = re.match(r"^([A-Za-z0-9_-]+):\s*(.*)$", line)
        if kv:
            value = kv.group(2).strip().strip('"').strip("'")
            fm[kv.group(1)] = value
    return fm


def heading_texts(text: str) -> list[str]:
    """Markdown heading text in document order, skipping frontmatter + fences."""
    body = FRONTMATTER_RE.sub("", text, count=1)
    headings: list[str] = []
    in_fence = False
    fence = ""
    for line in body.splitlines():
        stripped = line.strip()
        fence_match = FENCE_RE.match(stripped)
        if fence_match:
            token = fence_match.group(1)
            if not in_fence:
                in_fence = True
                fence = token[0]
            elif stripped.startswith(fence * 3):
                in_fence = False
            continue
        if in_fence:
            continue
        heading = HEADING_RE.match(line)
        if heading:
            headings.append(heading.group(1).strip())
    return headings


def referenced_paths(text: str) -> list[str]:
    """Pack-relative paths the SKILL.md body points at (backtick code spans)."""
    refs: list[str] = []
    for raw in BACKTICK_RE.findall(text):
        candidate = raw.strip().replace("\\", "/").strip("/")
        if not candidate or candidate == "SKILL.md":
            continue
        looks_like_path = "/" in candidate or Path(candidate).suffix
        if looks_like_path and candidate not in refs:
            refs.append(candidate)
    return refs


def pack_files(pack: Path) -> list[str]:
    return [
        p.relative_to(pack).as_posix()
        for p in sorted(pack.rglob("*"))
        if p.is_file() and p.relative_to(pack).as_posix() != "SKILL.md"
    ]


def render_skill_md(name: str, description: str, extra: list[str]) -> str:
    if extra:
        files_block = "\n".join(f"- `{rel}`" for rel in extra)
    else:
        files_block = "- （暂无附加文件；按需新增 implement.md / review.md / rules.md / examples.md / scripts/ 等）"
    return f"""---
name: {name}
description: {description}
---

{GENERATED_MARKER} (scaffold skeleton — replace placeholders with real content).

# {title_from_name(name)}

<!-- TODO(agent): 适用场景与触发词；何时使用本 skill。 -->

## 模式
- implement：实现相关代码/文档时，按需加载实现细节。
- review：审查相关产物时，按需加载审查 checklist。

## 上下文优先级（保证脱离 Superpowers 也能独立使用）
1. 当前上下文已提供的项目规范。
2. 用户明确指定的规范文档。
3. 本地可发现的项目文档。
4. 本 skill 的通用流程。

缺少项目专属规范时先询问，不要假设项目规则。

## 包内文件（按需加载）
{files_block}
"""


def render_extra_stub(rel: str) -> str:
    suffix = Path(rel).suffix
    if suffix in (".md", ".markdown", ".mdx"):
        return f"# {title_from_name(Path(rel).stem)}\n\n<!-- TODO(agent): 内容 -->\n"
    if suffix == ".py":
        return "#!/usr/bin/env python3\n"
    if suffix == ".sh":
        return "#!/usr/bin/env bash\n"
    return ""


def render_card(name: str, title: str, triggers: str) -> str:
    return (
        f"<!-- wiki-section:{name} -->\n"
        f"## {title}\n\n"
        f"适用：{triggers}\n\n"
        f"实现或审查相关产物时，**必须使用 skill：`{name}`**。\n"
        f"<!-- /wiki-section:{name} -->"
    )


def upsert_section(text: str, section_id: str, block: str) -> str:
    open_marker = f"<!-- wiki-section:{section_id} -->"
    close_marker = f"<!-- /wiki-section:{section_id} -->"
    block = block.strip()
    if open_marker in text and close_marker in text:
        start = text.index(open_marker)
        end = text.index(close_marker) + len(close_marker)
        return text[:start] + block + text[end:]
    return text.rstrip() + "\n\n" + block + "\n"


def regenerate_companion_index(leaf: Path) -> Path | None:
    out = index_path_for(leaf)
    existing = out.read_text(encoding="utf-8") if out.is_file() else None
    content = generate_index(leaf, existing)
    if content is None:
        return None
    write_text_lf(out, content)
    return out


def _auto_block_lines(text: str) -> list[str]:
    if AUTO_START in text and AUTO_END in text:
        start = text.index(AUTO_START) + len(AUTO_START)
        end = text.index(AUTO_END)
        return [line.rstrip() for line in text[start:end].splitlines() if line.strip()]
    return []


def ensure_index_ref(index_path: Path, ref: str, intro: str) -> bool:
    """Ensure an index.md auto-block lists `ref`. Returns True if it changed."""
    if index_path.is_file():
        text = index_path.read_text(encoding="utf-8")
    else:
        index_path.parent.mkdir(parents=True, exist_ok=True)
        text = intro.rstrip() + "\n\n" + AUTO_START + "\n" + AUTO_END + "\n"
    line = f"- `{ref}`"
    existing = _auto_block_lines(text)
    if line in existing:
        if not index_path.is_file():
            write_text_lf(index_path, text)
            return True
        return False
    existing.append(line)
    content = "\n".join(dict.fromkeys(existing))
    write_text_lf(index_path, replace_auto_section(text, content))
    return True


def _is_indexed(root_path: Path, target: Path) -> bool:
    graph = build_wiki_index_graph(root_path)
    resolved = {p.resolve() for p in graph.leaves} | {p.resolve() for p in graph.indexes}
    return target.resolve() in resolved


def ensure_discoverable(root_path: Path, skills_md: Path) -> list[str]:
    """Add only the missing index links so skills.md is reachable from root index."""
    changed: list[str] = []
    guides_index = skills_md.parent / "index.md"
    if not _is_indexed(root_path, guides_index):
        if ensure_index_ref(root_path / "index.md", "guides/", ROOT_INTRO):
            changed.append("index.md -> guides/")
    if not _is_indexed(root_path, skills_md):
        if ensure_index_ref(guides_index, skills_md.name, GUIDES_INTRO):
            changed.append("guides/index.md -> skills.md")
    return changed


def emit(result: dict[str, Any], as_json: bool) -> None:
    if as_json:
        print(json.dumps(result, ensure_ascii=False, indent=2))
        return
    command = result.get("command")
    if command in ("scaffold", "convert"):
        print(f"{command}: {result.get('skillName') or result.get('target')}")
        if result.get("created"):
            print("  created: " + ", ".join(result["created"]))
        if result.get("skipped"):
            print("  skipped: " + ", ".join(result["skipped"]))
        if result.get("carriedFiles"):
            print("  carried: " + ", ".join(result["carriedFiles"]))
        if result.get("uncovered"):
            print(f"  uncovered: {len(result['uncovered'])} item(s) not yet represented")
    elif command == "register-card":
        print(f"register-card: {result['skillName']} -> {result['cardPath']}")
        print(f"  discoverable: {result['discoverable']}")
    elif command == "validate":
        print(f"validate: {'ok' if result['ok'] else 'FAILED'}")
        for err in result.get("errors", []):
            print(f"  error: {err}")
        for warn in result.get("warnings", []):
            print(f"  warning: {warn}")


# --------------------------------------------------------------------------- #
# Commands
# --------------------------------------------------------------------------- #
def cmd_scaffold(args: argparse.Namespace) -> None:
    project = resolve_project(args)
    name = require_name(args.name)
    extra = parse_files(args.files)
    pack = project / SKILLS_DIR_REL / name
    pack.mkdir(parents=True, exist_ok=True)

    created: list[str] = []
    skipped: list[str] = []
    skill_md = pack / "SKILL.md"
    if skill_md.exists() and not args.force:
        skipped.append("SKILL.md")
    else:
        write_text_lf(skill_md, render_skill_md(name, args.description or DEFAULT_DESCRIPTION, extra))
        created.append("SKILL.md")

    for rel in extra:
        dest = pack / rel
        if dest.exists() and not args.force:
            skipped.append(rel)
            continue
        dest.parent.mkdir(parents=True, exist_ok=True)
        write_text_lf(dest, render_extra_stub(rel))
        created.append(rel)

    emit(
        {
            "command": "scaffold",
            "skillName": name,
            "packDir": str(pack),
            "created": created,
            "skipped": skipped,
        },
        args.json,
    )


def resolve_source(src: Path) -> tuple[Path, Path]:
    src = src.resolve()
    if src.is_dir():
        skill_md = src / "SKILL.md"
        if not skill_md.is_file():
            raise ScaffoldError(f"source skill dir has no SKILL.md: {src}")
        return src, skill_md
    if src.is_file():
        if src.name != "SKILL.md":
            raise ScaffoldError(f"source must be a SKILL.md or its directory: {src}")
        return src.parent, src
    raise ScaffoldError(f"source not found: {src}")


def source_inventory(src_dir: Path, src_skill: Path) -> dict[str, Any]:
    text = src_skill.read_text(encoding="utf-8")
    bundled = [
        p.relative_to(src_dir).as_posix()
        for p in sorted(src_dir.rglob("*"))
        if p.is_file() and p.relative_to(src_dir).as_posix() != "SKILL.md"
    ]
    return {
        "headings": heading_texts(text),
        "sectionIds": list_section_ids(text),
        "bundledFiles": bundled,
    }


def coverage_gaps(inventory: dict[str, Any], target: Path) -> list[dict[str, str]]:
    target_md = "\n".join(
        p.read_text(encoding="utf-8")
        for p in sorted(target.rglob("*.md"))
        if p.is_file()
    )
    gaps: list[dict[str, str]] = []
    for heading in inventory["headings"]:
        if heading and heading not in target_md:
            gaps.append({"type": "heading", "value": heading})
    for rel in inventory["bundledFiles"]:
        if not (target / rel).exists():
            gaps.append({"type": "file", "value": rel})
    return gaps


def cmd_convert(args: argparse.Namespace) -> None:
    project = resolve_project(args)
    src_dir, src_skill = resolve_source(Path(args.src))
    fm = parse_frontmatter(src_skill.read_text(encoding="utf-8"))
    name = require_name(args.name or fm.get("name") or src_dir.name)
    extra = parse_files(args.files)

    target = project / SKILLS_DIR_REL / name
    staging = False
    if target.resolve() == src_dir.resolve():
        target = project / SKILLS_DIR_REL / f"{name}.converted"
        staging = True
    target.mkdir(parents=True, exist_ok=True)

    # Carry over every bundled file (scripts/, assets, ...) except SKILL.md — never lose them.
    carried: list[str] = []
    for path in sorted(src_dir.rglob("*")):
        if path.is_dir():
            continue
        rel = path.relative_to(src_dir).as_posix()
        if rel == "SKILL.md":
            continue
        dest = target / rel
        dest.parent.mkdir(parents=True, exist_ok=True)
        if dest.exists() and dest.read_bytes() == path.read_bytes():
            continue
        shutil.copy2(path, dest)
        carried.append(rel)

    created: list[str] = []
    skipped: list[str] = []
    skill_md = target / "SKILL.md"
    if not skill_md.exists() or args.force:
        write_text_lf(skill_md, render_skill_md(name, fm.get("description") or DEFAULT_DESCRIPTION, extra))
        created.append("SKILL.md")
    else:
        skipped.append("SKILL.md")
    for rel in extra:
        dest = target / rel
        if dest.exists() and not args.force:
            skipped.append(rel)
            continue
        dest.parent.mkdir(parents=True, exist_ok=True)
        write_text_lf(dest, render_extra_stub(rel))
        created.append(rel)

    inventory = source_inventory(src_dir, src_skill)
    uncovered = coverage_gaps(inventory, target)

    emit(
        {
            "command": "convert",
            "source": str(src_dir),
            "target": str(target),
            "skillName": name,
            "staging": staging,
            "replacedOriginal": False,
            "carriedFiles": carried,
            "created": created,
            "skipped": skipped,
            "inventory": inventory,
            "uncovered": uncovered,
        },
        args.json,
    )
    if args.strict and uncovered:
        raise ScaffoldError(
            f"coverage incomplete: {len(uncovered)} source item(s) not yet represented in target pack"
        )


def cmd_register_card(args: argparse.Namespace) -> None:
    project = resolve_project(args)
    name = require_name(args.name)
    root = select_wiki_root(project, args.wiki_root, create=True)
    guides = root.path / "guides"
    skills_md = guides / "skills.md"

    operation = WIKI_OPERATION_UPDATE if skills_md.is_file() else WIKI_OPERATION_CREATE
    enforce_wiki_update_authorization(
        project,
        root,
        operation,
        authorized_update=args.authorized_update,
        authorized_create=args.authorized_create,
    )

    guides.mkdir(parents=True, exist_ok=True)
    if not skills_md.is_file():
        write_text_lf(skills_md, SKILLS_INTRO)

    title = args.title or title_from_name(name)
    triggers = args.triggers or "（补充触发场景关键词）"
    write_text_lf(
        skills_md,
        upsert_section(skills_md.read_text(encoding="utf-8"), name, render_card(name, title, triggers)),
    )

    companion = regenerate_companion_index(skills_md)
    linkage = ensure_discoverable(root.path, skills_md)

    graph = build_wiki_index_graph(root.path)
    discoverable = skills_md.resolve() in {p.resolve() for p in graph.leaves}

    emit(
        {
            "command": "register-card",
            "skillName": name,
            "wikiRoot": root.name,
            "cardPath": str(skills_md),
            "companionIndex": str(companion) if companion else None,
            "linkageChanged": linkage,
            "discoverable": discoverable,
        },
        args.json,
    )
    if not discoverable:
        raise ScaffoldError("discovery card written but skills.md is not reachable from the wiki index")


def cmd_validate(args: argparse.Namespace) -> None:
    project = resolve_project(args)
    errors: list[str] = []
    warnings: list[str] = []

    if args.pack_dir:
        pack = Path(args.pack_dir).resolve()
        name = args.name
    elif args.name:
        name = require_name(args.name)
        pack = project / SKILLS_DIR_REL / name
    else:
        raise ScaffoldError("validate requires --name or --pack-dir")

    skill_md = pack / "SKILL.md"
    if not skill_md.is_file():
        errors.append(f"SKILL.md missing under {pack}")
    else:
        body = skill_md.read_text(encoding="utf-8")
        fm = parse_frontmatter(body)
        if not fm.get("name"):
            errors.append("SKILL.md frontmatter missing name")
        if not fm.get("description"):
            errors.append("SKILL.md frontmatter missing description")
        referenced = referenced_paths(body)
        for rel in referenced:
            if not (pack / rel).exists():
                errors.append(f"SKILL.md references missing file: {rel}")
        for rel in pack_files(pack):
            if rel not in referenced:
                warnings.append(f"pack file not referenced from SKILL.md (won't load on demand): {rel}")
        for md in sorted(pack.rglob("*.md")):
            if md.name == "SKILL.md":
                continue
            if not md.read_text(encoding="utf-8").strip():
                errors.append(f"empty markdown file: {md.relative_to(pack).as_posix()}")

    if name and not args.skip_discovery:
        root = select_wiki_root(project, args.wiki_root)
        skills_md = root.path / "guides" / "skills.md"
        if not skills_md.is_file():
            errors.append("guides/skills.md missing (run register-card)")
        else:
            skills_text = skills_md.read_text(encoding="utf-8")
            for marker_error in validate_section_markers(skills_text):
                errors.append(f"skills.md section markers: {marker_error}")
            if name not in list_section_ids(skills_text):
                errors.append(f"no discovery card section for {name!r} in guides/skills.md")
            if not index_path_for(skills_md).is_file():
                errors.append("guides/skills.index.md missing (companion index not generated)")
            graph = build_wiki_index_graph(root.path)
            if skills_md.resolve() not in {p.resolve() for p in graph.leaves}:
                errors.append("guides/skills.md is not reachable from the wiki index")

    if args.src:
        src_dir, src_skill = resolve_source(Path(args.src))
        for gap in coverage_gaps(source_inventory(src_dir, src_skill), pack):
            errors.append(f"coverage gap ({gap['type']}): {gap['value']}")

    ok = not errors
    emit(
        {"command": "validate", "ok": ok, "errors": errors, "warnings": warnings},
        args.json,
    )
    if not ok:
        sys.exit(1)


# --------------------------------------------------------------------------- #
# CLI
# --------------------------------------------------------------------------- #
def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="Scaffold / convert best-practice skill packs.")
    parser.add_argument("--project-root", default=None, help="Project root (default: discovered from CWD).")
    parser.add_argument("--json", action="store_true", help="Emit a JSON result object.")
    sub = parser.add_subparsers(dest="command", required=True)

    p_scaffold = sub.add_parser("scaffold", help="Create a new pack skeleton.")
    p_scaffold.add_argument("--name", required=True)
    p_scaffold.add_argument("--description", default=None)
    p_scaffold.add_argument("--files", default=None, help="Comma-separated pack-relative paths (open set).")
    p_scaffold.add_argument("--force", action="store_true", help="Overwrite existing files.")
    p_scaffold.set_defaults(func=cmd_scaffold)

    p_convert = sub.add_parser("convert", help="Stage a layered pack from an existing skill (non-destructive).")
    p_convert.add_argument("--from", dest="src", required=True, help="Existing SKILL.md or its directory.")
    p_convert.add_argument("--name", default=None)
    p_convert.add_argument("--files", default=None)
    p_convert.add_argument("--force", action="store_true")
    p_convert.add_argument("--strict", action="store_true", help="Fail if any source content is uncovered.")
    p_convert.set_defaults(func=cmd_convert)

    p_card = sub.add_parser("register-card", help="Upsert the wiki discovery card for a skill.")
    p_card.add_argument("--name", required=True)
    p_card.add_argument("--wiki-root", choices=["project", "shared"], default="project")
    p_card.add_argument("--title", default=None)
    p_card.add_argument("--triggers", default=None)
    p_card.add_argument("--authorized-update", action="store_true")
    p_card.add_argument("--authorized-create", action="store_true")
    p_card.set_defaults(func=cmd_register_card)

    p_validate = sub.add_parser("validate", help="Validate pack invariants + discoverability.")
    p_validate.add_argument("--name", default=None)
    p_validate.add_argument("--pack-dir", default=None)
    p_validate.add_argument("--wiki-root", choices=["project", "shared"], default="project")
    p_validate.add_argument("--from", dest="src", default=None, help="Optional source for coverage check.")
    p_validate.add_argument("--skip-discovery", action="store_true")
    p_validate.set_defaults(func=cmd_validate)

    return parser


def main(argv: list[str] | None = None) -> int:
    _configure_stdio()
    parser = build_parser()
    args = parser.parse_args(argv)
    try:
        args.func(args)
    except (ScaffoldError, PermissionError, ValueError) as exc:
        print(f"Error: {exc}", file=sys.stderr)
        return 1
    return 0


if __name__ == "__main__":
    sys.exit(main())
